  String filePath = stats.get("absolutePath");
  File source = new File(filePath);

  if (!source.exists()) {
    source.createNewFile();
  }


log.error(" Pre-iteraotor HR Data Archiving : ");


  HashMap myHashMap = new HashMap(); 

