  CustomGlobal.put("FileStatMap",myHashMap); 

  return null;

  String currentDate = new SimpleDateFormat("EEEE_ddMMMMyyyy_a").format(new Date());
  Path archivePath = Paths.get("D:\\SailPoint\\csv files\\Test"+"\\EmployeesCF_"+currentDate+".csv"); 
  //File.copy(filePath,archivePath,StandardCopyOption.REPLACE_EXISTING);
